Here are pytest‑style unit tests covering happy path, edge cases, and error cases (invalid input):

```python
import pytest
from your_module import flatten

def test_flatten_simple():
    assert flatten([1, 2, 3]) == [1, 2, 3]

def test_flatten_nested():
    assert flatten([1, [2, 3], 4]) == [1, 2, 3, 4]

def test_flatten_deeply_nested():
    assert flatten([1, [2, [3, [4]]]]) == [1, 2, 3, 4]

def test_flatten_with_empty_lists():
    assert flatten([1, [], [2, [], [3, []]]]) == [1, 2, 3]

def test_flatten_empty_input():
    assert flatten([]) == []

def test_flatten_mixed_types():
    assert flatten([1, "a", [True, [None]]]) == [1, "a", True, None]

def test_flatten_does_not_modify_original():
    data = [1, [2, 3]]
    original_copy = [1, [2, 3]]
    flatten(data)
    assert data == original_copy

def test_flatten_invalid_input_non_list():
    with pytest.raises(TypeError):
        flatten("not a list")

def test_flatten_invalid_input_partial_non_list():
    # This should NOT raise; non-lists are appended, only the top-level must be a list
    assert flatten([1, 2, "abc"]) == [1, 2, "abc"]
